CREATE TABLE store_product (id VARCHAR(36) PRIMARY KEY,name VARCHAR(240) NOT NULL,slug VARCHAR(180) NOT NULL UNIQUE,sku VARCHAR(100) NOT NULL UNIQUE,description TEXT,short_description TEXT,type VARCHAR(30) NOT NULL,status VARCHAR(30) NOT NULL,price DECIMAL(19,4) NOT NULL,compare_at_price DECIMAL(19,4),currency VARCHAR(3) NOT NULL,category VARCHAR(120),brand VARCHAR(120),featured_image_url VARCHAR(1000),gallery_json TEXT,attributes_json TEXT,seo_json TEXT,featured BOOLEAN NOT NULL,track_inventory BOOLEAN NOT NULL,allow_backorder BOOLEAN NOT NULL,stock_quantity INT NOT NULL,low_stock_threshold INT NOT NULL,weight_grams INT,digital_url VARCHAR(1000),created_at TIMESTAMP NOT NULL,updated_at TIMESTAMP NOT NULL);
CREATE TABLE store_variant (id VARCHAR(36) PRIMARY KEY,product_id VARCHAR(36) NOT NULL,name VARCHAR(180) NOT NULL,sku VARCHAR(100) NOT NULL UNIQUE,price DECIMAL(19,4),stock_quantity INT NOT NULL,option_values VARCHAR(500),image_url VARCHAR(1000),active BOOLEAN NOT NULL,created_at TIMESTAMP NOT NULL,CONSTRAINT fk_variant_product FOREIGN KEY(product_id) REFERENCES store_product(id) ON DELETE CASCADE);
CREATE TABLE store_inventory_movement (id VARCHAR(36) PRIMARY KEY,product_id VARCHAR(36) NOT NULL,variant_id VARCHAR(36),type VARCHAR(30) NOT NULL,quantity INT NOT NULL,reason VARCHAR(240) NOT NULL,reference_type VARCHAR(50),reference_id VARCHAR(80),created_at TIMESTAMP NOT NULL,CONSTRAINT fk_movement_product FOREIGN KEY(product_id) REFERENCES store_product(id),CONSTRAINT fk_movement_variant FOREIGN KEY(variant_id) REFERENCES store_variant(id));
CREATE INDEX ix_store_product_status ON store_product(status);CREATE INDEX ix_store_product_category ON store_product(category);CREATE INDEX ix_store_inventory_created ON store_inventory_movement(created_at);
